.planned-note { font-size: .75rem; color: var(--muted); grid-column: 1 / -1; }

/* ── Shared page layout ── */
.page-header { display: flex; flex-direction: column; gap: 6px; }
.page-header h1 { font-size: 1.8rem; font-weight: 800; letter-spacing: -.03em; }
.page-subtitle { font-size: .82rem; color: var(--muted); }
.page-footer { padding-top: 8px; border-top: 1px solid var(--border); }
.section-intro { font-size: .82rem; color: var(--muted); margin-bottom: 12px; line-height: 1.5; }
.empty-hint { font-size: .82rem; color: var(--muted); font-style: italic; }

/* ── ConfidenceBar ── */
.confidence-bar { display: flex; align-items: center; gap: 10px; padding: 10px 14px; background: var(--panel); border: 1px solid var(--border); border-radius: var(--radius); }
.confidence-label { font-size: .72rem; font-weight: 700; color: var(--muted); text-transform: uppercase; letter-spacing: .06em; flex-shrink: 0; }
.confidence-track { flex: 1; height: 6px; background: var(--panel2); border-radius: 3px; overflow: hidden; }
.confidence-fill { height: 100%; border-radius: 3px; transition: width .4s ease; }
.confidence-pct { font-size: .8rem; font-weight: 700; flex-shrink: 0; min-width: 36px; text-align: right; }
.confidence-section { margin-bottom: 4px; }

/* ── FactorCard (shared across Love / Career / Personality) ── */
.factors-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(240px, 1fr)); gap: 12px; }
.factor-card { background: var(--panel); border: 1px solid var(--border); border-radius: var(--radius); padding: 16px; display: flex; flex-direction: column; gap: 8px; }
.factor-card--highlight { border-color: var(--accent); }
.factor-card--tension { border-color: var(--warn); }
.factor-card-header { display: flex; align-items: center; justify-content: space-between; gap: 8px; }
.factor-label { font-size: .78rem; font-weight: 700; text-transform: uppercase; color: var(--muted); letter-spacing: .05em; flex: 1; }
.factor-value { font-size: .92rem; line-height: 1.5; }
.factor-note { font-size: .72rem; color: var(--muted); line-height: 1.4; font-style: italic; }

/* ── LovePage ── */
.love-page { display: flex; flex-direction: column; gap: 36px; }
.love-headline { font-size: 1.05rem; line-height: 1.7; font-style: italic; color: var(--accent2); }
.factors-section { display: flex; flex-direction: column; gap: 12px; }
.factors-section h2 { font-size: .88rem; font-weight: 700; text-transform: uppercase; color: var(--muted); letter-spacing: .08em; }
.flows-easily h2 { color: var(--ok); }
.needs-awareness h2 { color: var(--warn); }
.wuxing-section { display: flex; flex-direction: column; gap: 12px; }
.wuxing-section h2 { font-size: .88rem; font-weight: 700; text-transform: uppercase; color: var(--muted); letter-spacing: .08em; }
.wuxing-content { background: var(--panel); border: 1px solid var(--border); border-radius: var(--radius); padding: 20px; display: flex; flex-direction: column; gap: 10px; }
.wuxing-cycle { display: flex; align-items: center; gap: 10px; }
.wuxing-cycle-label { font-size: 1rem; font-weight: 700; color: var(--accent2); }
.wuxing-desc { font-size: .88rem; line-height: 1.6; }
.wuxing-disclaimer { font-size: .72rem; color: var(--muted); font-style: italic; }
.missing-section { display: flex; flex-direction: column; gap: 12px; }
.missing-section h2 { font-size: .88rem; font-weight: 700; text-transform: uppercase; color: var(--muted); letter-spacing: .08em; }

/* ── CareerFinancePage ── */
.career-finance-page { display: flex; flex-direction: column; gap: 28px; }
.tab-bar { display: flex; gap: 2px; border-bottom: 1px solid var(--border); }
.tab-btn { background: none; border: none; border-bottom: 2px solid transparent; padding: 10px 20px; font-size: .88rem; font-weight: 600; color: var(--muted); cursor: pointer; transition: color .15s, border-color .15s; margin-bottom: -1px; }
.tab-btn:hover { color: var(--text); }
.tab-btn--active { color: var(--accent); border-bottom-color: var(--accent); }
.tab-panel { display: flex; flex-direction: column; }
.tab-panel--hidden { display: none; }
.tab-content { display: flex; flex-direction: column; gap: 24px; padding-top: 16px; }
.tab-content h3 { font-size: .8rem; font-weight: 700; text-transform: uppercase; color: var(--muted); letter-spacing: .07em; margin-bottom: -8px; }
.finance-disclaimer { background: var(--warn)11; border: 1px solid var(--warn)44; border-radius: var(--radius); padding: 14px 16px; font-size: .78rem; color: var(--warn); line-height: 1.5; }

/* ── PersonalityPage ── */
.personality-page { display: flex; flex-direction: column; gap: 36px; }
.personality-headline { font-size: 1.05rem; line-height: 1.7; font-style: italic; color: var(--accent2); margin-top: 4px; }
.primary-layer, .coherence-layer, .supporting-layer, .missing-layer { display: flex; flex-direction: column; gap: 12px; }
.primary-layer h2, .coherence-layer h2, .supporting-layer h2, .missing-layer h2 { font-size: .88rem; font-weight: 700; text-transform: uppercase; letter-spacing: .08em; color: var(--muted); }
.primary-layer h2 { color: var(--accent); }
.coherence-layer h2 { color: var(--accent2); }
.contradiction-note { background: var(--panel2); border: 1px solid var(--accent2)44; border-radius: var(--radius); padding: 16px; display: flex; flex-direction: column; gap: 8px; }
.contradiction-note h4 { font-size: .82rem; font-weight: 700; color: var(--accent2); }
.contradiction-note p { font-size: .82rem; color: var(--muted); line-height: 1.5; }
.missing-content { display: flex; flex-direction: column; gap: 8px; }

/* ── Mobile (375px) ── */
@media (max-width: 480px) {
  #app { padding: 20px 12px 60px; }
  .bazi-pillars { grid-template-columns: repeat(2, 1fr); }
  .factors-grid { grid-template-columns: 1fr; }
  .tab-btn { padding: 8px 14px; font-size: .82rem; }
  .page-header h1 { font-size: 1.4rem; }
}

