.transit-loading { padding: 2rem; text-align: center; color: var(--muted-foreground, #666); }
.transit-error { padding: 1rem; background: #fef2f2; border: 1px solid #fecaca; border-radius: 8px; color: #b91c1c; margin: 1rem 0; }

.transit-section-title { font-size: 1.25rem; font-weight: 600; margin-bottom: 1rem; }
.transit-active-houses { font-size: 0.9rem; margin-bottom: 1rem; color: var(--muted-foreground, #666); }
.transit-active-houses strong { color: var(--foreground, #111); }

