.transit-planet-card { background: var(--card, #fff); border: 1px solid var(--border, #e5e7eb); border-radius: 10px; padding: 0.875rem 0.75rem; display: flex; flex-direction: column; align-items: center; gap: 0.25rem; }
.transit-planet-symbol { font-size: 1.4rem; line-height: 1; }
.transit-planet-name { font-size: 0.7rem; color: var(--muted-foreground, #666); font-weight: 600; letter-spacing: 0.04em; text-transform: uppercase; }
.transit-planet-sign { font-size: 0.85rem; font-weight: 600; }
.transit-planet-deg { font-size: 0.75rem; color: var(--muted-foreground, #888); }
.transit-retro { font-size: 0.7rem; color: #f97316; font-weight: 700; }

.transit-week-strip { display: grid; grid-template-columns: repeat(7, 1fr); gap: 0.5rem; overflow-x: auto; }
.transit-day-col { background: var(--card, #fff); border: 1px solid var(--border, #e5e7eb); border-radius: 8px; padding: 0.75rem 0.5rem; display: flex; flex-direction: column; gap: 0.5rem; min-width: 0; }
.transit-day-col--today { border-color: #6366f1; background: #f5f3ff; }
.transit-day-date { font-size: 0.7rem; font-weight: 600; color: var(--muted-foreground, #666); text-align: center; white-space: nowrap; }
.transit-day-col--today .transit-day-date { color: #6366f1; }
.transit-day-planets { display: flex; flex-direction: column; gap: 0.2rem; }
.transit-day-planet { display: flex; gap: 0.25rem; align-items: center; font-size: 0.75rem; }
.tdp-sym { font-size: 0.9rem; }
.tdp-sign { color: var(--muted-foreground, #666); }
.tdp-retro { color: #f97316; font-size: 0.65rem; font-weight: 700; }
.transit-day-intensity { display: flex; align-items: flex-end; gap: 1px; height: 30px; margin-top: auto; }
.tdi-bar { flex: 1; background: #6366f1; border-radius: 2px 2px 0 0; min-height: 2px; transition: height 0.3s; }
.tdi-bar--empty { background: var(--border, #e5e7eb); height: 2px; }

.transit-now-section { margin-bottom: 2rem; }
.transit-timeline-section { margin-bottom: 2rem; }

@media (max-width: 600px) {
  .transit-week-strip { grid-template-columns: repeat(7, minmax(80px, 1fr)); }
