.daily-back-link:hover { text-decoration: underline; }
.daily-title { font-size: 1.75rem; font-weight: 700; margin: 0.5rem 0 0; }
.daily-date { font-size: 0.95rem; color: var(--muted); margin: 0.25rem 0 0; }

.daily-loading { padding: 2rem; text-align: center; color: var(--muted); }
.daily-error { padding: 1rem; background: var(--panel); border: 1px solid var(--bad); border-radius: var(--radius); color: var(--bad); text-align: left; margin: 1rem 0; }
.daily-error a { color: var(--bad); }

.daily-content { display: flex; flex-direction: column; gap: 1.5rem; }

.daily-section { background: var(--panel); border: 1px solid var(--border); border-radius: var(--radius); padding: 1.5rem; }
.daily-section--western { border-left: 4px solid var(--accent); }
.daily-section--eastern { border-left: 4px solid var(--accent2); }
.daily-section--fusion { border-left: 4px solid var(--ok); }

.daily-section-title { font-size: 1.1rem; font-weight: 700; margin: 0 0 0.75rem; }
.daily-summary { margin: 0 0 0.75rem; line-height: 1.6; }
.daily-synthesis { font-style: italic; color: var(--muted); margin: 0.5rem 0; line-height: 1.6; }

.daily-themes { display: flex; flex-wrap: wrap; gap: 0.4rem; margin-bottom: 0.75rem; }
.daily-theme-tag { background: var(--panel2); border: 1px solid var(--border); border-radius: 99px; padding: 0.2rem 0.75rem; font-size: 0.8rem; font-weight: 600; }

.daily-callout { padding: 0.625rem 0.875rem; border-radius: var(--radius); font-size: 0.9rem; margin-bottom: 0.5rem; border: 1px solid var(--border); background: var(--panel2); }

.daily-note { font-size: 0.85rem; color: var(--muted); margin: 0.25rem 0; }
.daily-note--jieqi { font-style: italic; }

.daily-action { background: var(--panel2); border: 1px solid var(--accent); border-radius: var(--radius); padding: 0.75rem 1rem; margin-top: 0.75rem; font-weight: 500; }
.daily-pushworthy { background: var(--panel2); border: 1px solid var(--ok); border-radius: var(--radius); padding: 0.5rem 1rem; margin-top: 0.5rem; font-weight: 600; font-size: 0.9rem; color: var(--ok); }

.daily-pillar { font-weight: 700; font-size: 1.1rem; }
.daily-meta { font-size: 0.8rem; color: var(--muted); text-align: center; margin: 0.5rem 0 0; }
